const ocrData = $json.ocr || {};
const safetyData = $json.safety || {};
const drugNames = ($json.drug_names || []).filter(Boolean).join(' and ');
const fallbackQuery = $('Webhook - Receive Mobile Request').first().json.body.query || '';
const queryParts = [];
if (drugNames) queryParts.push(drugNames + ' interaction');
if (safetyData.dosing_errors && safetyData.dosing_errors.length > 0) queryParts.push('dosing safety check');
const finalQuery = queryParts.join(' and ') || fallbackQuery;
return [{ json: { body: { query: finalQuery, mode: 'cloud' } } }];

const data = $json;
const alertIcons = {
  CRITICAL: '\u{1f6a8}',
  WARNING:  '\u26a0\ufe0f',
  INFO:     '\u2139\ufe0f',
  SAFE:     '\u2705'
};
const severityColors = {
  CRITICAL: '\u{1f534}',
  WARNING:  '\u{1f7e1}',
  INFO:     '\u{1f535}',
  SAFE:     '\u{1f7e2}'
};

const icon  = alertIcons[data.alert_level]  || '\u2139\ufe0f';
const color = severityColors[data.alert_level] || '\u{1f535}';
const drugs = (data.drug_name || []).map(d => d.toUpperCase()).join(' + ');
const sources = (data.bnf_source_page || [])
  .map(s => `BNF80 p.${s.page}`).join(', ') || 'No BNF sources';

// Truncate rationale for messenger
const rationale = (data.clinical_rationale_the_why || '')
  .replace(/\[Mechanism[^\]]*\]:/g, '\u{1f9ea} Mechanism:')
  .substring(0, 600)
  .trim();

const msg = [
  `${icon} *PHARMA ALERT* ${color}`,
  `*Severity:* ${data.interaction_severity || 'NONE'}`,
  `*Drugs:* ${drugs || data.query}`,
  '',
  `*Clinical Rationale:*`,
  rationale,
  '',
  `*BNF Sources:* ${sources}`,
  `*RAG Confidence:* ${data.confidence_pct}%`,
  '',
  `\_Query:\_  ${data.query}`,
  '',
  '\u{1f4cb} _Verify with a licensed pharmacist before clinical decisions_'
].join('\n');

return [{ json: { telegram_text: msg, alert_level: data.alert_level, structured: data } }];
